import{_ as a,c as e,o as r,a9 as t}from"./chunks/framework.sBgkVKsu.js";const m=JSON.parse('{"title":"驿站与文档","description":"","frontmatter":{},"headers":[],"relativePath":"article/自我介绍.md","filePath":"article/自我介绍.md","lastUpdated":1734270870000}'),l={name:"article/自我介绍.md"},h=t('<h1 id="驿站与文档" tabindex="-1">驿站与文档 <a class="header-anchor" href="#驿站与文档" aria-label="Permalink to &quot;驿站与文档&quot;">​</a></h1><h2 id="首页" tabindex="-1">首页 <a class="header-anchor" href="#首页" aria-label="Permalink to &quot;首页&quot;">​</a></h2><p>仓库主页：<a href="https://github.com/MinecraftEarthVillage/lezi" target="_blank" rel="noreferrer">https://github.com/MinecraftEarthVillage/lezi</a></p><p>想问其他问题可以进入我们的<a href="https://map.earthvillage.top/qqun.html" title="戳我" target="_blank" rel="noreferrer">群聊</a></p><h1 id="问-为什么会想记录乐子" tabindex="-1">问：为什么会想记录乐子 <a class="header-anchor" href="#问-为什么会想记录乐子" aria-label="Permalink to &quot;问：为什么会想记录乐子&quot;">​</a></h1><hr><p>答：最开始是因为记录<a href="https://map.earthvillage.top/MCBBS.mp4" target="_blank" rel="noreferrer">皇权论坛传奇</a>，这个视频在哔哩哔哩发布会导致封禁，而又没有其它的平台可用的，但这时候我还是只在群聊间传播，以及存放云盘，然后我们服务器里也出现过许多“人才语录”，长期存放在群相册。</p><p>后来在一些群里有看到一个叫“<a href="https://lezi.yizhan.wiki" target="_blank" rel="noreferrer">乐子驿站</a>”的东西，人家挂出了许多“名人”。然后和<a href="http://lezi.earthvillage.top/article/earth" target="_blank" rel="noreferrer">魔怔地球玩家</a>对骂的时候就萌生了这个想法，使用了同一个模板创建了地球村自己的档案，所以你在首页中可以看到MCBBS写的是“梦开始的地方”，而“魔怔地球”则在导航页第一个。</p><p>反正心态就开始转变了，你说这么滴骂乐子有啥用，给自己气到了又没好处，隔着屏幕你又不能打他，我就在想：有什么办法让他们更有价值呢？ 于是乐子文档就诞生了，~<s>啊吾就开始传播“快乐”了</s>~</p><hr><h1 id="问-什么是乐子" tabindex="-1">问：什么是乐子 <a class="header-anchor" href="#问-什么是乐子" aria-label="Permalink to &quot;问：什么是乐子&quot;">​</a></h1><p><em>方言，意思是快乐的事。</em> —— 百度百科</p><hr><p>很多乐子都是无知，但无知和乐子是不能划等号的</p><p>比如你可以不知道这个服务器是玩什么的,怎么玩，怎么挣游戏货币，怎么换创造体验时间</p><p>你找个群问：”请问这个服务器是怎么玩的，我的客户端是xxx，带了XXX MOD可以进吗 然后还可以截图什么的” 我相信会有人给你解答：你可以先···（BLBL）···告诉你一般流程，玩法，还有不能做的事情，怎么购买某样东西</p><p>但是如果你直接说：“这个服务器垃圾死了”、“L”、“鸽鸽我可以S人吗鸽鸽我可以开挂炸新人房子吗”···那你就是傻逼、乐子了</p><p>或者最显眼的几个地方写着域名、可用版本什么的，进来群还问“IP是什么呀”~~</p><p>说实话我也讲不明白，大概就是做出一些很弱智的行为，做出一些不符合共识的行为，那再追问弱智的行为是什么、共识是什么只是没完没了</p><hr><h1 id="问-什么是乐子人" tabindex="-1">问：什么是乐子人 <a class="header-anchor" href="#问-什么是乐子人" aria-label="Permalink to &quot;问：什么是乐子人&quot;">​</a></h1><p><em>释义：乐子人就是字面意思，以看乐子为目的的人。经典语录为“我看Vtuber就是图一乐，其他都不关心”。但是乐子人也分好几种，温和派是单纯吃瓜，看到各种新鲜事就赶紧前排看乐子，如果事件影响大了甚至还会化身理中客讨论一番。极端派是没有乐子，也要到处拱火，前排开团找乐子的人。甚至还有一些异端派，以看乐子为人生追求，他们不管圈子、不论主题，仿佛一个载满了开团武器的泥头车，把一个圈子搞臭了就去下一个圈子。</em></p><p>（来自小鸡词典）</p><p>看释义我是异端派了<a href="/icons/%E7%8C%AB%E7%8C%AB%E8%99%AB%E6%BB%9A%E5%8A%A8.gif"></a></p>',24),i=[h];function p(o,n,s,c,_,d){return r(),e("div",null,i)}const u=a(l,[["render",p]]);export{m as __pageData,u as default};
